/* transferMapper.insertMcpRequest */
INSERT INTO MCP_REQUEST_ADDITION@DL_CAN (
        REQUEST_KEY, ADDITION_KEY, ADDITION_NAME, RANTAL
)
SELECT
        REQUEST_KEY, ADDITION_KEY, ADDITION_NAME, RANTAL
FROM    MCP_REQUEST_ADDITION@DL_MCP
WHERE   REQUEST_KEY = #{requestKey}

/* transferMapper.insertMcpRequestClause */
INSERT INTO MCP_REQUEST_CLAUSE@DL_CAN (
        REQUEST_KEY, CD_GROUP_ID2, DOC_VER, SYS_RDATE
)
SELECT
        REQUEST_KEY, CD_GROUP_ID2, DOC_VER, SYS_RDATE
FROM    MCP_REQUEST_CLAUSE@DL_MCP
WHERE   REQUEST_KEY = #{requestKey}

/* transferMapper.insertMcpRequestDvcChg */
INSERT INTO MCP_REQUEST_DVC_CHG@DL_CAN (
        REQUEST_KEY, DVC_CHG_TYPE, DVC_CHG_RSN_CD,
        DVC_CHG_RSN_DTL_CD, REGST_DTTM
)
SELECT
        REQUEST_KEY, DVC_CHG_TYPE, DVC_CHG_RSN_CD,
        DVC_CHG_RSN_DTL_CD, REGST_DTTM
FROM    MCP_REQUEST_DVC_CHG@DL_MCP
WHERE   REQUEST_KEY = #{requestKey}

mapper.select:
SELECT  A.ORIGIN_DIR AS fileInfo
FROM    EMV_SCAN_FILE@DL_MCP A
WHERE   A.SCAN_ID = #{scanId}

/* transferMapper.getRequestKey */
SELECT  REQUEST_KEY as requestKey
        , SCAN_ID   as scanId
FROM    MSP_REQUEST
WHERE   CONTRACT_NUM = #{contractNum}

mapper.insert:
/* transferMapper.insertMspRequestAddition */
INSERT INTO MSP_REQUEST_ADDITION@DL_CAN (
        REQUEST_KEY, ADDITION_KEY, ADDITION_NAME, RANTAL
)
SELECT
        REQUEST_KEY, ADDITION_KEY, ADDITION_NAME, RANTAL
FROM    MSP_REQUEST_ADDITION A
WHERE   REQUEST_KEY = #{requestKey}
AND     NOT EXISTS ( SELECT 1 FROM MSP_REQUEST@DL_CAN WHERE REQUEST_KEY = A.REQUEST_KEY )

mapper.select:
/* transferMapper.getBanOtherCntrExist */

SELECT  COUNT(1)
FROM    MSP_JUO_SUB_INFO
WHERE   BAN = #{ban}
AND     CONTRACT_NUM <> #{contractNum}

mapper.update:
/* tranferMapper.updateMspRequestChange */
UPDATE  MSP_REQUEST_CHANGE
SET     NAME_CHANGE_NM       = CASE WHEN NAME_CHANGE_NM IS NOT NULL THEN '이관고객' ELSE '' END
        , NAME_CHANGE_TEL_MN = CASE WHEN NAME_CHANGE_TEL_MN IS NOT NULL THEN LPAD('*', LENGTH(NAME_CHANGE_TEL_MN), '*') ELSE '' END 
        , NAME_CHANGE_RRN    = CASE WHEN NAME_CHANGE_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(NAME_CHANGE_RRN), 1, 7) || '******') ELSE '' END
WHERE   REQUEST_KEY = #{requestKey}

/* tranferMapper.updateMspRequestDtl */
UPDATE  MSP_REQUEST_DTL
SET     MINOR_AGENT_NAME  = CASE WHEN MINOR_AGENT_NAME IS NOT NULL THEN '이관고객' ELSE '' END  
        , MINOR_AGENT_TEL = CASE WHEN MINOR_AGENT_TEL IS NOT NULL THEN SUBSTR(MINOR_AGENT_TEL, 1, 3) || LPAD('*', LENGTH(MINOR_AGENT_TEL) - 7, '*') || SUBSTR(MINOR_AGENT_TEL, -4) ELSE '' END
WHERE   REQUEST_KEY = #{requestKey}

/* tranferMapper.updateMspRequestMove */
UPDATE  MSP_REQUEST_MOVE
SET     MOVE_MOBILE_MN = CASE WHEN MOVE_MOBILE_MN IS NOT NULL THEN LPAD('*', LENGTH(MOVE_MOBILE_MN), '*') ELSE '' END
        , REQ_GUIDE_MN = CASE WHEN REQ_GUIDE_MN IS NOT NULL THEN LPAD('*', LENGTH(REQ_GUIDE_MN), '*') ELSE '' END
WHERE   REQUEST_KEY = #{requestKey}

/* tranferMapper.updateMspJuoSubInfoHist */
UPDATE  MSP_JUO_SUB_INFO_HIST
SET     USER_SSN               = CASE WHEN USER_SSN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(USER_SSN), 1, 7) || '******') ELSE '' END
        , SUB_ADR_SECONDARY_LN = CASE WHEN SUB_ADR_SECONDARY_LN IS NOT NULL THEN LPAD('*', LENGTH(SUB_ADR_SECONDARY_LN), '*') ELSE '' END
        , SUB_LINK_NAME        = CASE WHEN SUB_LINK_NAME IS NOT NULL THEN '이관고객' ELSE '' END
WHERE   CONTRACT_NUM = #{contractNum}

/* tranferMapper.updateMspJuoCusInfo */
UPDATE  MSP_JUO_CUS_INFO
SET     CUSTOMER_SSN                = CASE WHEN CUSTOMER_SSN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(CUSTOMER_SSN), 1, 7) || '******') ELSE '' END
        , CUSTOMER_ADR_SECONDARY_LN = CASE WHEN CUSTOMER_ADR_SECONDARY_LN IS NOT NULL THEN LPAD('*', LENGTH(CUSTOMER_ADR_SECONDARY_LN), '*') ELSE '' END
        , CUSTOMER_LINK_NAME        = CASE WHEN CUSTOMER_LINK_NAME IS NOT NULL THEN '이관고객' ELSE '' END
WHERE   CUSTOMER_ID = #{customerId}

/* tranferMapper.updateMspJuoCusInfoHist */
UPDATE  MSP_JUO_CUS_INFO_HIST
SET     CUSTOMER_SSN                = CASE WHEN CUSTOMER_SSN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(CUSTOMER_SSN), 1, 7) || '******') ELSE '' END
        , CUSTOMER_ADR_SECONDARY_LN = CASE WHEN CUSTOMER_ADR_SECONDARY_LN IS NOT NULL THEN LPAD('*', LENGTH(CUSTOMER_ADR_SECONDARY_LN), '*') ELSE '' END
        , CUSTOMER_LINK_NAME        = CASE WHEN CUSTOMER_LINK_NAME IS NOT NULL THEN '이관고객' ELSE '' END
WHERE   CUSTOMER_ID = #{customerId}

/* tranferMapper.updateMspJuoBanInfo */
UPDATE  MSP_JUO_BAN_INFO
SET     BAN_ADR_SECONDARY_LN = CASE WHEN BAN_ADR_SECONDARY_LN IS NOT NULL THEN LPAD('*', LENGTH(BAN_ADR_SECONDARY_LN), '*') ELSE '' END
        , BAN_LINK_NAME      = CASE WHEN BAN_LINK_NAME IS NOT NULL THEN '이관고객' ELSE '' END
WHERE   BAN = #{ban}

/* tranferMapper.updateMspJuoBanInfoHist */
UPDATE  MSP_JUO_BAN_INFO_HIST
SET     BAN_ADR_SECONDARY_LN = CASE WHEN BAN_ADR_SECONDARY_LN IS NOT NULL THEN LPAD('*', LENGTH(BAN_ADR_SECONDARY_LN), '*') ELSE '' END
        , BAN_LINK_NAME      = CASE WHEN BAN_LINK_NAME IS NOT NULL THEN '이관고객' ELSE '' END
WHERE   BAN = #{ban}

mapper.select:
/* transferMapper.getTmntCustDataList */

SELECT  A.CONTRACT_NUM  as contractNum
        , A.CUSTOMER_ID as customerId
        , A.BAN         as ban
FROM    MSP_JUO_SUB_INFO@DL_CAN A
WHERE   A.TRANSFER_DTTM < SYSDATE - #{stdrCnt}
